CREATE TABLE `sessions` (
	`id` varchar(255) NOT NULL,
	`userId` int NOT NULL,
	`expiresAt` timestamp NOT NULL,
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	CONSTRAINT `sessions_id` PRIMARY KEY(`id`)
);
ALTER TABLE `users` MODIFY COLUMN `openId` varchar(64);
ALTER TABLE `users` ADD `username` varchar(100);
ALTER TABLE `users` ADD `passwordHash` text;
ALTER TABLE `users` ADD CONSTRAINT `users_username_unique` UNIQUE(`username`);
ALTER TABLE `sessions` ADD CONSTRAINT `sessions_userId_users_id_fk` FOREIGN KEY (`userId`) REFERENCES `users`(`id`) ON DELETE no action ON UPDATE no action;

